module phase_shifter(  
    input [2:0] phase_not,  
    input control,  
    output reg [2:0] phase_out  
);  
    always @(*) begin  
        if (control)  
            phase_out = {phase_not[1:0], phase_not[2]}; // Shift left with wrap-around  
        else  
            phase_out = phase_not;  
    end  
endmodule
